`,xt(t.p,{children:"Virtual try-on (VTON) has advanced single-garment visualization, yet real-world fashion centers on full outfits with multiple garments, accessories, fine-grained categories, layering, and diverse styling, remaining beyond current VTON systems. Existing datasets are category-limited and lack outfit diversity. We introduce Garments2Look, the first large-scale multimodal dataset for outfit-level VTON, comprising 80K many-garments-toone-look pairs across 40 major categories and 300+ finegrained subcategories. Each pair includes an outfit with 3-12 reference garment images (Average 4.48), a model image wearing the outfit, and detailed item and try-on textual annotations. To balance authenticity and diversity, we propose a synthesis pipeline. It involves heuristically constructing outfit lists before generating try-on results, with the entire process subjected to strict automated filtering and human validation to ensure data quality. To probe task difficulty, we adapt SOTA VTON methods and general-purpose image editing models to establish baselines. Results show current methods struggle to try on complete outfits seamlessly and to infer correct layering and styling, leading to misalignment and artifacts."})]})}function lZ(e={}){const{wrapper:t}=e.components||{};return t?xt(t,{...e,children:xt(Xb,{...e})}):Xb(e)}const sZ={__name:"Abstract",setup(e){return(t,n)=>{const a=nt("el-divider"),o=nt("el-col"),l=nt("el-row");return x(),B("div",null,[K(a),K(l,{justify:"center"},{default:X(()=>[K(o,{xs:24,sm:20,md:16,lg:12,xl:12},{default:X(()=>[K(i(lZ))]),_:1})]),_:1})])}}};function Jb(e){const t={h1:"h1",img:"img",p:"p",strong:"strong",...e.components};return xt(Be,{children:[xt(t.h1,{children:"Comparison with existing datasets"}),`
